1	interface Item {
2	  type: string;
3	}
4	
5	interface QuoteStep {
6	  op: "quote";
7	  items: Item[];
8	}
9	
10	type Step = QuoteStep;
11	
12	interface Scenario {
13	  customer: { yearsWithMHPCO: number };
14	  steps: Step[];
15	}
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	};
24	
25	const FIRST_INSURANCE_NUMERATOR = 11;
26	const FIRST_INSURANCE_DENOMINATOR = 10;
27	const PROCESSING_FEE = 5;
28	
29	const COMPONENT_PREMIUM = 25;
30	const BLOCK_SIZE = 3;
31	const BLOCK_PREMIUM = 60;
32	const COMPONENT_TYPES = new Set(["rune"]);
33	
34	const componentBasePremium = (count: number): number => {
35	  const blocks = Math.floor(count / BLOCK_SIZE);
36	  const loose = count % BLOCK_SIZE;
37	  return blocks * BLOCK_PREMIUM + loose * COMPONENT_PREMIUM;
38	};
39	
40	const basePremium = (items: Item[]): number => {
41	  const componentCount = items.filter((item) => COMPONENT_TYPES.has(item.type)).length;
42	  const mainTotal = items
43	    .filter((item) => !COMPONENT_TYPES.has(item.type))
44	    .reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
45	  return mainTotal + componentBasePremium(componentCount);
46	};
47	
48	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
49	  const results = scenario.steps.map((step) => {
50	    const base = basePremium(step.items);
51	    const withFirstInsurance =
52	      (base * FIRST_INSURANCE_NUMERATOR) / FIRST_INSURANCE_DENOMINATOR;
53	    const premium = Math.ceil(withFirstInsurance + PROCESSING_FEE);
54	    return { premium };
55	  });
56	  return { results };
57	};
